## 🔧 详细实现方案

### 阶段 1：迁移系统核心 (Day 1-2)

#### 1.1 创建迁移追踪表

```typescript
// src/dashboard/models/migration-tracker.ts

import Database from 'better-sqlite3';

export interface Migration {
  id: number;
  name: string;
  version: string;
  applied_at: string;
  rollback_sql?: string;
}

export function createMigrationTable(db: Database.Database): void {
  db.exec(`
    CREATE TABLE IF NOT EXISTS schema_migrations (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      version TEXT NOT NULL UNIQUE,
      name TEXT NOT NULL,
      applied_at DATETIME NOT NULL DEFAULT (datetime('now')),
      rollback_sql TEXT,
      checksum TEXT NOT NULL,
      execution_time_ms INTEGER
    );

    CREATE INDEX IF NOT EXISTS idx_migrations_version 
      ON schema_migrations(version);
  `);
}

export function getAppliedMigrations(db: Database.Database): Migration[] {
  return db.prepare('SELECT * FROM schema_migrations ORDER BY version').all() as Migration[];
}

export function recordMigration(
  db: Database.Database,
  version: string,
  name: string,
  checksum: string,
  executionTimeMs: number,
  rollbackSql?: string
): void {
  db.prepare(`
    INSERT INTO schema_migrations (version, name, checksum, execution_time_ms, rollback_sql)
    VALUES (?, ?, ?, ?, ?)
  `).run(version, name, checksum, executionTimeMs, rollbackSql);
}

export function removeMigration(db: Database.Database, version: string): void {
  db.prepare('DELETE FROM schema_migrations WHERE version = ?').run(version);
}
```

#### 1.2 迁移系统核心逻辑

```typescript
// src/dashboard/migrations/index.ts

import Database from 'better-sqlite3';
import path from 'path';
import fs from 'fs';
import { createHash } from 'crypto';
import { getAppliedMigrations, recordMigration, removeMigration } from '../models/migration-tracker';

export interface MigrationFile {
  version: string;
  name: string;
  up: () => void;
  down: () => void;
  checksum: string;
}

export class MigrationSystem {
  constructor(private db: Database.Database, private migrationsDir: string) {}

  /**
   * 获取所有待执行的迁移
   */
  getPendingMigrations(): MigrationFile[] {
    const applied = new Set(getAppliedMigrations(this.db).map(m => m.version));
    const allMigrations = this.loadAllMigrations();
    return allMigrations.filter(m => !applied.has(m.version));
  }

  /**
   * 执行所有待执行的迁移
   */
  async migrate(): Promise<void> {
    const pending = this.getPendingMigrations();

    if (pending.length === 0) {
      console.log('✅ No pending migrations');
      return;
    }

    console.log(`📦 Applying ${pending.length} migration(s)...`);

    for (const migration of pending) {
      await this.applyMigration(migration);
    }

    console.log('✅ All migrations applied successfully');
  }

  /**
   * 回滚最后一个迁移
   */
  async rollback(): Promise<void> {
    const applied = getAppliedMigrations(this.db);

    if (applied.length === 0) {
      console.log('✅ No migrations to rollback');
      return;
    }

    const lastMigration = applied[applied.length - 1];
    const migrationFile = this.loadMigration(lastMigration.version);

    if (!migrationFile || !migrationFile.down) {
      throw new Error(`Cannot rollback migration ${lastMigration.version}: no down() defined`);
    }

    console.log(`⏪ Rolling back ${lastMigration.version}...`);

    const startTime = Date.now();
    this.db.transaction(() => {
      migrationFile.down();
      removeMigration(this.db, lastMigration.version);
    })();

    const executionTime = Date.now() - startTime;
    console.log(`⏪ Rollback completed in ${executionTime}ms`);
  }

  /**
   * 应用单个迁移
   */
  private async applyMigration(migration: MigrationFile): Promise<void> {
    console.log(`⬆️  Applying ${migration.version}: ${migration.name}...`);

    const startTime = Date.now();

    try {
      this.db.transaction(() => {
        migration.up();
        recordMigration(
          this.db,
          migration.version,
          migration.name,
          migration.checksum,
          Date.now() - startTime
        );
      })();

      const executionTime = Date.now() - startTime;
      console.log(`✅ ${migration.version} applied in ${executionTime}ms`);
    } catch (error) {
      console.error(`❌ Failed to apply ${migration.version}:`, error);
      throw error;
    }
  }

  /**
   * 加载所有迁移文件
   */
  private loadAllMigrations(): MigrationFile[] {
    const files = fs.readdirSync(this.migrationsDir)
      .filter(f => f.endsWith('.ts') && f !== 'index.ts' && f !== 'template.ts')
      .sort();

    return files.map(f => {
      const migration = require(path.join(this.migrationsDir, f));
      return {
        version: migration.version,
        name: migration.name,
        up: migration.up,
        down: migration.down,
        checksum: this.calculateChecksum(migration.up.toString())
      };
    });
  }

  /**
   * 加载单个迁移
   */
  private loadMigration(version: string): MigrationFile | null {
    const files = fs.readdirSync(this.migrationsDir);
    const file = files.find(f => f.startsWith(version));

    if (!file) return null;

    const migration = require(path.join(this.migrationsDir, file));
    return {
      version: migration.version,
      name: migration.name,
      up: migration.up,
      down: migration.down,
      checksum: this.calculateChecksum(migration.up.toString())
    };
  }

  /**
   * 计算迁移脚本校验和
   */
  private calculateChecksum(script: string): string {
    return createHash('sha256').update(script).digest('hex');
  }

  /**
   * 验证迁移完整性
   */
  validateMigrations(): { valid: boolean; issues: string[] } {
    const issues: string[] = [];
    const applied = getAppliedMigrations(this.db);
    const allMigrations = this.loadAllMigrations();

    // 检查是否缺少迁移文件
    const appliedVersions = new Set(applied.map(m => m.version));
    const existingVersions = new Set(allMigrations.map(m => m.version));

    for (const version of appliedVersions) {
      if (!existingVersions.has(version)) {
        issues.push(`Migration file for version ${version} is missing`);
      }
    }

    // 检查校验和
    for (const appliedMigration of applied) {
      const migration = allMigrations.find(m => m.version === appliedMigration.version);
      if (migration && migration.checksum !== appliedMigration.checksum) {
        issues.push(`Migration ${appliedMigration.version} checksum mismatch`);
      }
    }

    return {
      valid: issues.length === 0,
      issues
    };
  }
}
```

