### 阶段 3：数据库维护服务 (Day 5)

```typescript
// src/dashboard/services/database-maintenance.service.ts

import Database from 'better-sqlite3';
import pino from 'pino';

export class DatabaseMaintenanceService {
  constructor(
    private db: Database.Database,
    private logger: pino.Logger
  ) {}

  /**
   * 执行 VACUUM 优化数据库
   */
  async vacuum(): Promise<{ sizeBefore: number; sizeAfter: number; freed: number }> {
    this.logger.info('Starting database VACUUM...');

    const fs = require('fs');
    const sizeBefore = fs.statSync(this.db.filename).size;

    this.db.pragma('journal_mode = WAL');
    this.db.vacuum();

    const sizeAfter = fs.statSync(this.db.filename).size;
    const freed = sizeBefore - sizeAfter;

    this.logger.info({
      sizeBefore: (sizeBefore / 1024 / 1024).toFixed(2) + ' MB',
      sizeAfter: (sizeAfter / 1024 / 1024).toFixed(2) + ' MB',
      freed: (freed / 1024 / 1024).toFixed(2) + ' MB'
    }, 'VACUUM completed');

    return { sizeBefore, sizeAfter, freed };
  }

  /**
   * 分析数据库统计信息
   */
  async analyze(): Promise<void> {
    this.logger.info('Analyzing database statistics...');
    this.db.pragma('optimize');
    this.logger.info('Analysis completed');
  }

  /**
   * 检查数据库完整性
   */
  async checkIntegrity(): Promise<{ ok: boolean; result: string }> {
    this.logger.info('Checking database integrity...');
    const result = this.db.pragma('integrity_check') as string[];

    const ok = result.length === 1 && result[0] === 'ok';

    if (!ok) {
      this.logger.error({ result }, 'Integrity check failed');
    } else {
      this.logger.info('Integrity check passed');
    }

    return { ok, result: result.join(', ') };
  }

  /**
   * 执行数据清理
   */
  async cleanupOldData(): Promise<void> {
    this.logger.info('Starting data cleanup...');

    const config = this.db.prepare(`
      SELECT * FROM data_retention_config WHERE id = 1
    `).get() as any;

    const stats = {
      metrics: 0,
      logs: 0,
      iterations: 0,
      snapshots: 0
    };

    // 清理系统指标
    const metricsCutoff = new Date();
    metricsCutoff.setDate(metricsCutoff.getDate() - config.metrics_retention_days);

    const metricsResult = this.db.prepare(`
      DELETE FROM system_metrics 
      WHERE recorded_at < ?
    `).run(metricsCutoff.toISOString());
    stats.metrics = metricsResult.changes;

    // 清理日志
    const logsCutoff = new Date();
    logsCutoff.setDate(logsCutoff.getDate() - config.logs_retention_days);

    const logsResult = this.db.prepare(`
      DELETE FROM logs 
      WHERE timestamp < ?
    `).run(logsCutoff.toISOString());
    stats.logs = logsResult.changes;

    // 清理已完成的迭代
    const iterationsCutoff = new Date();
    iterationsCutoff.setDate(iterationsCutoff.getDate() - config.completed_iterations_retention_days);

    const iterationsResult = this.db.prepare(`
      DELETE FROM iterations 
      WHERE started_at < ? 
      AND status IN ('completed', 'failed', 'cancelled')
    `).run(iterationsCutoff.toISOString());
    stats.iterations = iterationsResult.changes;

    // 清理旧快照
    const snapshotsCutoff = new Date();
    snapshotsCutoff.setDate(snapshotsCutoff.getDate() - config.snapshots_retention_days);

    const snapshotsResult = this.db.prepare(`
      DELETE FROM code_snapshots 
      WHERE created_at < ?
    `).run(snapshotsCutoff.toISOString());
    stats.snapshots = snapshotsResult.changes;

    // 更新最后清理时间
    this.db.prepare(`
      UPDATE data_retention_config 
      SET last_cleanup_at = datetime('now')
      WHERE id = 1
    `).run();

    // 记录清理历史
    const totalDeleted = Object.values(stats).reduce((a, b) => a + b, 0);
    this.db.prepare(`
      INSERT INTO cleanup_history 
      (cleanup_type, records_deleted, started_at, completed_at)
      VALUES (?, ?, datetime('now', '-1 minute'), datetime('now'))
    `).run('scheduled', totalDeleted);

    this.logger.info({ stats }, 'Data cleanup completed');
  }

  /**
   * 获取数据库性能指标
   */
  async getPerformanceMetrics(): Promise<any> {
    const fs = require('fs');
    const dbSize = fs.statSync(this.db.filename).size;
    const pageCount = this.db.pragma('page_count', { simple: true });
    const freePages = this.db.pragma('freelist_count', { simple: true });
    const pageSize = this.db.pragma('page_size', { simple: true });

    // 检查未使用的索引
    const indexStats = this.db.prepare(`
      SELECT name 
      FROM sqlite_master 
      WHERE type = 'index' 
      AND name LIKE 'idx_%'
    `).all();

    return {
      databaseSize: {
        bytes: dbSize,
        mb: (dbSize / 1024 / 1024).toFixed(2),
        mbFormatted: `${(dbSize / 1024 / 1024).toFixed(2)} MB`
      },
      storage: {
        pageSize,
        pageCount,
        freePages,
        fragmentation: ((freePages / pageCount) * 100).toFixed(2) + '%'
      },
      indexes: {
        count: indexStats.length,
        names: indexStats.map((i: any) => i.name)
      }
    };
  }
}
```

