### 阶段 4：查询分析工具 (Day 6)

```typescript
// src/dashboard/utils/query-analyzer.ts

import Database from 'better-sqlite3';

export interface QueryAnalysis {
  sql: string;
  executionTime: number;
  rowsReturned: number;
  indexUsed: string | null;
  tableScan: boolean;
  explanation: any;
}

export class QueryAnalyzer {
  constructor(private db: Database.Database) {}

  /**
   * 分析查询执行计划
   */
  analyzeQuery(sql: string, params: any[] = []): QueryAnalysis {
    const startTime = Date.now();
    const stmt = this.db.prepare(sql);
    const result = stmt.all(...params);
    const executionTime = Date.now() - startTime;

    // 获取查询计划
    const plan = this.db.prepare(`EXPLAIN QUERY PLAN ${sql}`).all(...params);

    // 检查是否使用了索引
    const indexUsed = this.detectIndexUsage(plan);

    // 检查是否全表扫描
    const tableScan = this.detectTableScan(plan);

    return {
      sql,
      executionTime,
      rowsReturned: Array.isArray(result) ? result.length : 0,
      indexUsed,
      tableScan,
      explanation: plan
    };
  }

  /**
   * 获取慢查询列表
   */
  getSlowQueries(thresholdMs: number = 100): QueryAnalysis[] {
    const slowQueries: QueryAnalysis[] = [];

    // 常见查询列表
    const queries = [
      'SELECT * FROM iterations WHERE status = ? ORDER BY started_at DESC LIMIT 50',
      'SELECT * FROM iterations WHERE started_at > ?',
      'SELECT * FROM agent_states WHERE iteration_id = ?',
      'SELECT * FROM agent_states WHERE status = ?',
      'SELECT * FROM system_metrics WHERE recorded_at > ? ORDER BY recorded_at DESC',
      'SELECT * FROM logs WHERE level = ? ORDER BY timestamp DESC LIMIT 100'
    ];

    for (const sql of queries) {
      const analysis = this.analyzeQuery(sql, ['test']);
      if (analysis.executionTime > thresholdMs) {
        slowQueries.push(analysis);
      }
    }

    return slowQueries;
  }

  /**
   * 生成索引建议
   */
  generateIndexSuggestions(): string[] {
    const suggestions: string[] = [];

    // 分析 EXPLAIN QUERY PLAN 输出
    const commonQueries = [
      { sql: 'SELECT * FROM iterations WHERE status = ? AND started_at > ?', hint: 'idx_iterations_status_time' },
      { sql: 'SELECT * FROM agent_states WHERE iteration_id = ? AND agent_type = ?', hint: 'idx_agent_states_iteration_type' },
      { sql: 'SELECT * FROM logs WHERE iteration_id = ? AND timestamp > ?', hint: 'idx_logs_iteration_time' }
    ];

    for (const query of commonQueries) {
      const plan = this.db.prepare(`EXPLAIN QUERY PLAN ${query.sql}`).all();
      const needsIndex = plan.some((p: any) => p.detail && p.detail.includes('SCAN'));

      if (needsIndex) {
        suggestions.push(`Consider adding index: ${query.hint} for query: ${query.sql}`);
      }
    }

    return suggestions;
  }

  /**
   * 获取数据库索引统计
   */
  getIndexStats(): Array<{ name: string; tableName: string; columns: string }> {
    const indexes = this.db.prepare(`
      SELECT 
        i.name as name,
        m.name as tableName,
        GROUP_CONGINE(ic.name) as columns
      FROM sqlite_master i
      JOIN sqlite_master m ON i.tbl_name = m.name
      JOIN pragma_index_info(i.name) ic
      WHERE i.type = 'index' AND i.name LIKE 'idx_%'
      GROUP BY i.name
    `).all();

    return indexes.map((idx: any) => ({
      name: idx.name,
      tableName: idx.tableName,
      columns: idx.columns
    }));
  }

  private detectIndexUsage(plan: any[]): string | null {
    for (const row of plan) {
      if (row.detail && row.detail.includes('SEARCH')) {
        const match = row.detail.match(/USING INDEX (.+?) /);
        return match ? match[1] : 'unknown';
      }
    }
    return null;
  }

  private detectTableScan(plan: any[]): boolean {
    return plan.some(row => row.detail && row.detail.includes('SCAN'));
  }
}
