// src/dashboard/cli.ts
import { DatabaseMaintenanceService } from './services/database-maintenance.service';
import { MigrationSystem } from './migrations';

export async function runMaintenanceCommand(command: string) {
  const db = initDatabase(process.env.DATABASE_PATH);
  const logger = pino({ level: 'info' });

  const maintenance = new DatabaseMaintenanceService(db, logger);
  const migrations = new MigrationSystem(db, 'src/dashboard/migrations');

  switch (command) {
    case 'migrate':
      await migrations.migrate();
      break;
    case 'rollback':
      await migrations.rollback();
      break;
    case 'vacuum':
      await maintenance.vacuum();
      break;
    case 'cleanup':
      await maintenance.cleanupOldData();
      break;
    case 'analyze':
      await maintenance.analyze();
      break;
    case 'check':
      const integrity = await maintenance.checkIntegrity();
      console.log('Integrity:', integrity);
      break;
    default:
      console.log('Available commands: migrate, rollback, vacuum, cleanup, analyze, check');
  }
}
